func mergePlanStatus(status ui.TopicStatus, inst *session.Instance, started bool) ui.TopicStatus {
	if inst.TaskFile == "" {
		return status
	}
	if started && !inst.Paused() {
		if inst.IsReviewer {
			status.HasNotification = true
		} else {
			status.HasRunning = true
		}
	}
	if inst.Notified && inst.IsReviewer {
		status.HasNotification = true
	}
	return status
}

